//! InterviewAssist Phase 0 sandbox capability catalog (generated by
//! `wasm4pm-sandbox-pack`).
//!
//! First-class source rendered from `sbx:SandboxCapability` individuals in
//! the pack ontology. To change a capability, edit the pack ontology and
//! re-run `ggen sync`. Catalog surface only: this crate does not execute
//! anything -- the real subprocess actuator (isolation, timeout,
//! stdout/exit-code capture, receipting) lives in wasm4pm's own
//! `wasm4pm-sandbox` crate, which implements the `SandboxActuator` trait
//! from `sandbox_actuator_trait.rs`.

/// Stable identifier for every sandbox capability in this catalog.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum CapabilityId {
    /// `compile_python`
    CompilePython,
    /// `compile_rust`
    CompileRust,
    /// `execute_python`
    ExecutePython,
    /// `execute_rust`
    ExecuteRust,
    /// `run_cargo_test`
    RunCargoTest,
    /// `run_pytest`
    RunPytest,
}

/// The kind of sandbox operation a capability performs.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Operation {
    Compile,
    Execute,
    Test,
}

/// Static metadata for one sandbox capability.
pub struct CapabilityInfo {
    pub id: CapabilityId,
    pub language: &'static str,
    pub operation: Operation,
    pub doc: &'static str,
    pub timeout_ms: u64,
    pub authority_scope: &'static str,
    /// Capabilities that must have already produced a `Pass` outcome in the
    /// same session before this one may be dispatched (`sbx:requiresCapability`).
    pub requires: &'static [CapabilityId],
}

/// Every catalogued sandbox capability, in stable (id-sorted) order.
pub const CAPABILITY_CATALOG: &[CapabilityInfo] = &[
    CapabilityInfo {
        id: CapabilityId::CompilePython,
        language: "python",
        operation: Operation::Compile,
        doc: "Syntax-checks a candidate Python source file via `python -m py_compile` -- Python has no separate build artifact, so this is the compile-equivalent admission gate.",
        timeout_ms: 5000,
        authority_scope: "sandbox.compile",
        requires: &[],
    },
    CapabilityInfo {
        id: CapabilityId::CompileRust,
        language: "rust",
        operation: Operation::Compile,
        doc: "Builds a candidate Rust crate via `cargo build` in an isolated subprocess.",
        timeout_ms: 60000,
        authority_scope: "sandbox.compile",
        requires: &[],
    },
    CapabilityInfo {
        id: CapabilityId::ExecutePython,
        language: "python",
        operation: Operation::Execute,
        doc: "Runs a compiled-clean Python source file in an isolated subprocess and captures stdout/stderr/exit status.",
        timeout_ms: 10000,
        authority_scope: "sandbox.execute",
        requires: &[CapabilityId::CompilePython, ],
    },
    CapabilityInfo {
        id: CapabilityId::ExecuteRust,
        language: "rust",
        operation: Operation::Execute,
        doc: "Runs the binary produced by compile_rust in an isolated subprocess and captures stdout/stderr/exit status.",
        timeout_ms: 10000,
        authority_scope: "sandbox.execute",
        requires: &[CapabilityId::CompileRust, ],
    },
    CapabilityInfo {
        id: CapabilityId::RunCargoTest,
        language: "rust",
        operation: Operation::Test,
        doc: "Runs `cargo test` against a candidate crate in an isolated subprocess (compiles internally, so it has no separate compile precondition).",
        timeout_ms: 60000,
        authority_scope: "sandbox.execute",
        requires: &[],
    },
    CapabilityInfo {
        id: CapabilityId::RunPytest,
        language: "python",
        operation: Operation::Test,
        doc: "Runs `pytest` against a candidate solution plus its test file in an isolated subprocess.",
        timeout_ms: 20000,
        authority_scope: "sandbox.execute",
        requires: &[CapabilityId::CompilePython, ],
    },
];

impl CapabilityId {
    /// The wire-level capability id string used in receipts and dispatch.
    pub fn as_str(self) -> &'static str {
        match self {
            Self::CompilePython => "compile_python",
            Self::CompileRust => "compile_rust",
            Self::ExecutePython => "execute_python",
            Self::ExecuteRust => "execute_rust",
            Self::RunCargoTest => "run_cargo_test",
            Self::RunPytest => "run_pytest",
        }
    }

    /// Look up this capability's static metadata in `CAPABILITY_CATALOG`.
    pub fn info(self) -> &'static CapabilityInfo {
        CAPABILITY_CATALOG.iter().find(|c| c.id == self).expect("every CapabilityId has a CAPABILITY_CATALOG entry")
    }
}

/// Parse a wire-level capability id string into its `CapabilityId` variant.
pub fn from_capability_id(s: &str) -> Option<CapabilityId> {
    match s {
        "compile_python" => Some(CapabilityId::CompilePython),
        "compile_rust" => Some(CapabilityId::CompileRust),
        "execute_python" => Some(CapabilityId::ExecutePython),
        "execute_rust" => Some(CapabilityId::ExecuteRust),
        "run_cargo_test" => Some(CapabilityId::RunCargoTest),
        "run_pytest" => Some(CapabilityId::RunPytest),
        _ => None,
    }
}
